interface Cursor { createdAt: string; id: string; }

function decodeCursor(raw?: string): Cursor | null {
  if (!raw) return null;
  const parsed = JSON.parse(Buffer.from(raw, 'base64url').toString('utf8')) as Cursor;
  if (!parsed.id || Number.isNaN(Date.parse(parsed.createdAt))) throw new Error('bad_cursor');
  return parsed;
}

async function listTickets(cursorText?: string) {
  const cursor = decodeCursor(cursorText);
  const where = cursor ? 'WHERE (created_at, id) < ($1::timestamptz, $2)' : '';
  const params = cursor ? [cursor.createdAt, cursor.id, 50] : [50];
  return db.query(`SELECT * FROM tickets ${where} ORDER BY created_at DESC, id DESC LIMIT $${params.length}`, params);
}

